import os
import secrets
import hashlib
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# In-memory storage (use database in production)
users_db = {}
tokens_db = {}

TOKEN_EXPIRY_HOURS = 24


def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(16)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return f"{salt}${pwd_hash.hex()}"


def verify_password(stored_password, provided_password):
    salt, pwd_hash = stored_password.split('$')
    return stored_password == hash_password(provided_password, salt)


def generate_token():
    return secrets.token_urlsafe(32)


def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            if auth_header.startswith('Bearer '):
                token = auth_header.split(' ')[1]
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        if token not in tokens_db:
            return jsonify({'message': 'Invalid token'}), 401
        
        token_data = tokens_db[token]
        
        if datetime.now() > token_data['expires_at']:
            del tokens_db[token]
            return jsonify({'message': 'Token has expired'}), 401
        
        return f(token_data['username'], *args, **kwargs)
    
    return decorated


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password are required'}), 400
    
    username = data['username'].strip()
    password = data['password']
    
    if len(username) < 3:
        return jsonify({'message': 'Username must be at least 3 characters'}), 400
    
    if len(password) < 8:
        return jsonify({'message': 'Password must be at least 8 characters'}), 400
    
    if username in users_db:
        return jsonify({'message': 'User already exists'}), 409
    
    users_db[username] = {
        'password': hash_password(password),
        'created_at': datetime.now()
    }
    
    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password are required'}), 400
    
    username = data['username'].strip()
    password = data['password']
    
    if username not in users_db:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    if not verify_password(users_db[username]['password'], password):
        return jsonify({'message': 'Invalid credentials'}), 401
    
    token = generate_token()
    tokens_db[token] = {
        'username': username,
        'created_at': datetime.now(),
        'expires_at': datetime.now() + timedelta(hours=TOKEN_EXPIRY_HOURS)
    }
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': TOKEN_EXPIRY_HOURS * 3600
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user):
    token = request.headers['Authorization'].split(' ')[1]
    
    if token in tokens_db:
        del tokens_db[token]
    
    return jsonify({'message': 'Logout successful'}), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user):
    return jsonify({
        'message': 'This is a protected endpoint',
        'user': current_user
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(current_user):
    user_data = users_db.get(current_user)
    
    if not user_data:
        return jsonify({'message': 'User not found'}), 404
    
    return jsonify({
        'username': current_user,
        'created_at': user_data['created_at'].isoformat()
    }), 200


